// User Layer - Entry Point
const userData = {
  userId: $input.first().json.userId || 'user_' + Date.now(),
  timestamp: new Date().toISOString(),
  requestType: $input.first().json.requestType || 'browse',
  sessionData: {
    browser: $input.first().json.browser || 'unknown',
    location: $input.first().json.location || 'unknown'
  }
};

return [{ json: userData }];

